import psycopg2
import json

def lambda_handler(event, context):
    conn = None
    try:
        # Connect to your postgres DB
        conn = psycopg2.connect("host=internal-db.us-east-1.rds.amazonaws.com dbname=production user=admin password=password port=5432")
        
        cur = conn.cursor()
        cur.execute('SELECT * FROM your_table')
        
        rows = cur.fetchall()
        columns = [desc[0] for desc in cur.description]
        
        result = []
        for row in rows:
            result.append(dict(zip(columns, row)))
        
        return {
            'statusCode': 200,
            'body': json.dumps(result)
        }
    except (Exception, psycopg2.DatabaseError) as error:
        print(error)
        return {
            'statusCode': 500,
            'body': json.dumps('Internal Server Error')
        }
    finally:
        if conn is not None:
            conn.close()